parts.args:
{"title":"fix(remediation): remove empty REQUIRED_API_BASE env var causing nginx proxy_pass failure","body":"Root cause: The REQUIRED_API_BASE environment variable is set to an empty string in the Deployment manifest, causing nginx to fail with "invalid number of arguments in proxy_pass directive" when rendering the template configuration.

Evidence: 2026/06/05 00:48:34 [emerg] 1#1: invalid number of arguments in "proxy_pass" directive in /etc/nginx/conf.d/default.conf:4

Affected resources: default/vigil-app-6895f8ff98-mlt74, Deployment/vigil-app"}

parts.content:
apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: cluster-apps
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default
